// Helper function to get skills for a job title with fuzzy matching
export const getSkillsForJobTitle = (jobTitle: string): string[] => {
  // Direct match
  if (enhancedSkillTree[jobTitle]) {
    return enhancedSkillTree[jobTitle];
  }

  // Fuzzy matching for similar job titles
  const titleLower = jobTitle.toLowerCase();
  
  // Try exact matches with different casing
  const exactMatch = Object.keys(enhancedSkillTree).find(key => 
    key.toLowerCase() === titleLower
  );
  if (exactMatch) return enhancedSkillTree[exactMatch];

  // Try partial matches
  const partialMatch = Object.keys(enhancedSkillTree).find(key => 
    key.toLowerCase().includes(titleLower) || 
    titleLower.includes(key.toLowerCase())
  );
  if (partialMatch) return enhancedSkillTree[partialMatch];

  // Try keyword-based matching
  const keywordMatch = Object.keys(enhancedSkillTree).find(key => {
    const keyWords = key.toLowerCase().split(' ');
    const titleWords = titleLower.split(' ');
    return keyWords.some(kw => titleWords.some(tw => tw.includes(kw) || kw.includes(tw)));
  });
  if (keywordMatch) return enhancedSkillTree[keywordMatch];

  console.log(`No skills found for job title: ${jobTitle}`);
  return [];
};

// Function to get all available job titles
export const getAllJobTitles = (): string[] => {
  return Object.keys(enhancedSkillTree);
};

// Function to get skills statistics
export const getSkillsStats = () => {
  const jobTitles = Object.keys(enhancedSkillTree);
  const allSkills = Object.values(enhancedSkillTree).flat();
  const uniqueSkills = [...new Set(allSkills)];
  
  return {
    totalJobTitles: jobTitles.length,
    totalSkillEntries: allSkills.length,
    uniqueSkills: uniqueSkills.length,
    averageSkillsPerJob: Math.round(allSkills.length / jobTitles.length * 100) / 100
  };
};
